namespace sv_8d7251c2a8aa44c8b998130ae635d39b.Services;

public sealed class RecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with tomato, mozzarella, and basil.", 25),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta and parmesan.", 30),
            new(3, "Tiramisu", "Layered coffee-flavored Italian dessert.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken in a creamy spiced tomato sauce.", 50),
            new(5, "Palak Paneer", "Cottage cheese cubes in a smooth spinach gravy.", 35),
            new(6, "Biryani", "Fragrant layered rice dish with spices and tender meat.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-grilled pork tacos with pineapple and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and chili.", 10),
            new(9, "Churros", "Fried dough pastry coated in cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (RecipesByCuisine.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject RecipeService RecipeService
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (error is not null)
{
    <div class="alert alert-danger">
        <p>@error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="LoadAsync">Retry</button>
    </div>
}
else if (recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (isLoading)
    {
        <p><em>Refreshing…</em></p>
    }

    @{
        var displayed = Sort == "popular"
            ? recipes.OrderBy(r => r.PrepTimeMinutes).ToList()
            : recipes.OrderByDescending(r => r.Id).ToList();
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var r in displayed)
            {
                <tr>
                    <td>@r.Title</td>
                    <td>@r.Description</td>
                    <td>@r.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private CancellationTokenSource? cts;
    private int? loadedCuisineId;
    private List<Recipe>? recipes;
    private bool isLoading;
    private string? error;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == loadedCuisineId)
        {
            return; // Only sort changed — no reload
        }

        loadedCuisineId = CuisineId;
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }

        cts = new CancellationTokenSource();
        var cancellationToken = cts.Token;

        error = null;
        isLoading = true;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);
            recipes = result;
        }
        catch (OperationCanceledException ex) when (!cancellationToken.IsCancellationRequested)
        {
            Logger.LogWarning(ex, "Timed out loading recipes for cuisine {CuisineId}", CuisineId);
            error = "The request timed out. Please try again.";
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Self-cancellation (parameter change or disposal) — let ComponentBase handle it.
            throw;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}", CuisineId);
            error = "Unable to load recipes. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }
    }
}

